+        assert!(
+            cli.is_ok(),
+            "--include-attachments must parse even when hidden: {:?}",
+            cli.err()
+        );
+        if let Ok(ref parsed) = cli {
+            if let Some(Commands::Pages {
+                include_attachments,
+                ..
+            }) = &parsed.command
+            {
+                assert!(include_attachments, "flag should be true when passed");
